SELECT year, species, SUM(quota) AS total_quota
FROM allocation
GROUP BY year, species;

SELECT shift_direction 
FROM distributional_shifts 
WHERE species = 'Cobia' AND location = '1' AND year = 2017;

SELECT component_type, location, description 
FROM spatial_components 
WHERE ecological_zone = 'Coastal' AND fishing_pressure = 'Medium';

SELECT state, AVG(average_trip_expenditure) AS avg_expenditure_per_trip 
FROM recreational_business_profits 
GROUP BY state;

SELECT r.business_name, d.location
FROM recreational_business_profits r
INNER JOIN distributional_shifts d ON r.fish_species_targeted = d.species AND r.state = d.location;

SELECT business_name, state, profit_margin, year
FROM recreational_business_profits
WHERE total_revenue > 200000 AND year = 2017;

SELECT species, sector
FROM allocation
WHERE remaining_quota < 0.20 * quota;

SELECT COUNT(*)
FROM distributional_shifts
WHERE species = 'Summer Flounder' AND shift_direction = 'North/South';
